// Usage: import { defineVitestConfig } from '@ai-whisperers/test-vitest/config'
//   export default defineVitestConfig(__dirname)

import { defineConfig } from 'vitest/config'
import react from '@vitejs/plugin-react'
import path from 'path'

interface VitestConfigOptions {
  /** Working directory for path resolution (pass __dirname) */
  dir?: string
  /** Custom src directory name (default: 'src') */
  srcDir?: string
  /** Whether to enable React plugin */
  react?: boolean
  /** Extra test include patterns */
  include?: string[]
  /** Extra setup files */
  setupFiles?: string[]
  /** Custom vitest config overrides */
  overrides?: Record<string, any>
}

export function defineVitestConfig(options: VitestConfigOptions = {}) {
  const {
    dir = process.cwd(),
    srcDir = 'src',
    react: useReact = true,
    include = [],
    setupFiles = [],
    overrides = {},
  } = options

  return defineConfig({
    plugins: useReact ? [react()] : [],
    test: {
      environment: 'jsdom',
      globals: true,
      setupFiles: [
        require.resolve('@ai-whisperers/test-vitest/dist/setup.js'),
        ...setupFiles,
      ],
      include: [
        `${srcDir}/**/*.{test,spec}.{ts,tsx}`,
        `__tests__/**/*.{test,spec}.{ts,tsx}`,
        ...include,
      ],
      css: false,
      coverage: {
        provider: 'v8',
        reporter: ['text', 'lcov', 'html'],
        include: [`${srcDir}/**/*.{ts,tsx}`],
        exclude: [
          `${srcDir}/**/*.{test,spec}.{ts,tsx}`,
          `${srcDir}/**/types.ts`,
          `${srcDir}/**/*.d.ts`,
        ],
      },
      ...overrides,
    },
    resolve: {
      alias: {
        '@': path.resolve(dir, srcDir),
        '@ai-whisperers/test-vitest': path.resolve(__dirname, '..'),
      },
    },
  })
}
