// Adds jest-dom matchers, global mocks, and test utilities

import '@testing-library/jest-dom/vitest'

// Mock global fetch
if (typeof globalThis !== 'undefined' && !globalThis.fetch) {
  globalThis.fetch = async () =>
    new Response(JSON.stringify({}), { status: 200, headers: { 'content-type': 'application/json' } })
}

// Mock console.error to fail tests on unexpected errors
const originalConsoleError = console.error
beforeEach(() => {
  console.error = (...args: any[]) => {
    const msg = args.join(' ')
    // Allow React act() warnings and known non-critical messages
    if (
      msg.includes('ReactDOMTestUtils.act') ||
      msg.includes('Inside a test was not wrapped in act') ||
      msg.includes('An update to')?.endsWith('inside a test was not wrapped in act')
    ) {
      return
    }
    originalConsoleError(...args)
  }
})
afterEach(() => {
  console.error = originalConsoleError
})

