type DeepPartial<T> = { [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P] }

import { generateProduct, type Product } from './product'
import { generateUser, type User } from './user'

export interface OrderItem {
  productId: string
  productName: string
  quantity: number
  unitPrice: number
  total: number
}

export interface Order {
  id: string
  userId: string
  userEmail: string
  items: OrderItem[]
  subtotal: number
  shipping: number
  discount: number
  total: number
  status: 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled'
  paymentMethod: string
  paymentStatus: 'pending' | 'paid' | 'failed' | 'refunded'
  shippingAddress: {
    street: string
    city: string
    state: string
    zip: string
    country: string
  }
  notes: string
  createdAt: string
  updatedAt: string
}

let _orderCounter = 0

export function generateOrder(overrides: DeepPartial<Order> = {}): Order {
  _orderCounter++
  const items = overrides.items ?? [
    { productId: 'prod_1', productName: 'Product 1', quantity: 2, unitPrice: 50000, total: 100000 },
  ]
  const subtotal = items.reduce((sum: number, i: any) => sum + (i.total ?? i.quantity * i.unitPrice), 0)
  const shipping = overrides.shipping ?? 15000
  const discount = overrides.discount ?? 0

  return {
    id: overrides.id ?? `ord_${_orderCounter}`,
    userId: overrides.userId ?? 'user_1',
    userEmail: overrides.userEmail ?? '[REDACTED_EMAIL]',
    items,
    subtotal,
    shipping,
    discount,
    total: subtotal + shipping - discount,
    status: overrides.status ?? 'pending',
    paymentMethod: overrides.paymentMethod ?? 'credit_card',
    paymentStatus: overrides.paymentStatus ?? 'pending',
    shippingAddress: overrides.shippingAddress ?? {
      street: 'Av. Principal 123',
      city: 'Asunción',
      state: 'Central',
      zip: '1000',
      country: 'PY',
    },
    notes: overrides.notes ?? '',
    createdAt: overrides.createdAt ?? new Date().toISOString(),
    updatedAt: overrides.updatedAt ?? new Date().toISOString(),
  }
}

export function generateOrderFromProduct(
  product: Product = generateProduct(),
  user: User = generateUser(),
  quantity = 1
): Order {
  const items: OrderItem[] = [{
    productId: product.id,
    productName: product.name,
    quantity,
    unitPrice: product.price,
    total: product.price * quantity,
  }]
  return generateOrder({
    userId: user.id,
    userEmail: user.email,
    items,
  })
}

export function generateOrderList(count: number, overrides: DeepPartial<Order> = {}): Order[] {
  return Array.from({ length: count }, () => generateOrder(overrides))
}
