import { defineConfig, devices } from '@playwright/test'

interface PlaywrightConfigOptions {
  webUrl: string
  outputDir?: string
  testDir?: string
  retries?: number
  workers?: number
  timeout?: number
  projects?: string[]
}

export function definePlaywrightConfig(options: PlaywrightConfigOptions) {
  const {
    webUrl = 'http://localhost:3000',
    outputDir = 'test-results',
    testDir = 'tests/e2e',
    retries = 2,
    workers = 4,
    timeout = 30000,
  } = options

  return defineConfig({
    testDir,
    fullyParallel: true,
    forbidOnly: !!process.env.CI,
    retries: process.env.CI ? retries : 0,
    workers: process.env.CI ? workers : undefined,
    reporter: [
      ['html', { outputFolder: `${outputDir}/html` }],
      ['list'],
    ],
    use: {
      baseURL: webUrl,
      trace: 'on-first-retry',
      screenshot: 'only-on-failure',
      video: 'retain-on-failure',
    },
    projects: [
      {
        name: 'chromium',
        use: { ...devices['Desktop Chrome'] },
      },
      {
        name: 'firefox',
        use: { ...devices['Desktop Firefox'] },
      },
      {
        name: 'mobile-chrome',
        use: { ...devices['Pixel 5'] },
      },
    ],
    outputDir,
  })
}
