import { Page, expect } from '@playwright/test'

export class HomePage {
  constructor(public readonly page: Page) {}

  async goto() {
    await this.page.goto('/')
  }

  async getTitle() {
    return this.page.title()
  }

  async clickWhatsAppFloat() {
    const whatsapp = this.page.locator('[data-testid="whatsapp-float"]')
    await whatsapp.click()
  }

  async search(query: string) {
    const searchInput = this.page.locator('[data-testid="search-input"]')
    await searchInput.fill(query)
    await searchInput.press('Enter')
  }
}

export class ProductPage {
  constructor(public readonly page: Page) {}

  async goto(slug: string) {
    await this.page.goto(`/producto/${slug}`)
  }

  async addToCart() {
    await this.page.locator('[data-testid="add-to-cart"]').click()
  }

  async getPrice() {
    return this.page.locator('[data-testid="product-price"]').textContent()
  }
}

export class CartPage {
  constructor(public readonly page: Page) {}

  async goto() {
    await this.page.goto('/carrito')
  }

  async getItemCount() {
    const text = await this.page.locator('[data-testid="cart-count"]').textContent()
    return text ? parseInt(text, 10) : 0
  }

  async proceedToCheckout() {
    await this.page.locator('[data-testid="checkout-button"]').click()
  }
}

export class CheckoutPage {
  constructor(public readonly page: Page) {}

  async goto() {
    await this.page.goto('/checkout')
  }

  async fillShippingInfo(info: { name: string; email: string; phone: string }) {
    await this.page.locator('[name="name"]').fill(info.name)
    await this.page.locator('[name="email"]').fill(info.email)
    await this.page.locator('[name="phone"]').fill(info.phone)
  }

  async submitOrder() {
    await this.page.locator('[data-testid="submit-order"]').click()
  }
}

export class AdminPage {
  constructor(public readonly page: Page) {}

  async goto() {
    await this.page.goto('/admin')
  }

  async login(email: string, password: [REDACTED] {
    await this.page.locator('[name="email"]').fill(email)
    await this.page.locator('[name="password"]').fill(password)
    await this.page.locator('[type="submit"]').click()
  }

  async navigateTo(section: string) {
    await this.page.locator(`[data-testid="nav-${section}"]`).click()
  }
}
